 (given) {$M$ is midpoint of $\overline{AB}$};
 {Given};

 (def) {$AM = MB$};
 {Def. of midpoint};

 (add) {$AM + MB = AB$};
 {Segment Addition};

 (sub) {$2 \cdot AM = AB$};
 {Substitution};

 (div) {$AM = \frac{1}{2}AB$};
 {Division Property};

 (given) – (def);
 (def) – (add);
 (add) – (sub);
 (def) |- (sub);
